#include <bits/stdc++.h>
using namespace std;
const int N=1e6+6;
int n,a[N],s[N],lm[N],rm[N],ans;
int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++){
		scanf("%d",&a[i]);
		s[i]=s[i-1]+a[i];
	}
	lm[1]=s[1];
	for(int i=2;i<=n;i++)
		lm[i]=min(lm[i-1],s[i]);
	rm[n]=s[n];
	for(int i=n-1;i;i--)
		rm[i]=min(rm[i+1],s[i]);
	for(int i=1;i<=n;i++)
		ans+=(rm[i]-s[i-1]>=0 && lm[i]+(s[n]-s[i-1])>=0);
	printf("%d",ans);
	return 0;
}
